const source = $input.first()?.json ?? {};
const pick = (...values) => values.find((value) => value !== undefined && value !== null && String(value).trim() !== '');
const clean = (value) => {
  const picked = pick(value);
  return picked === undefined ? '' : String(picked).trim();
};
const member = clean(source.member ?? source.query?.member ?? source.params?.member);
const product = clean(source.product ?? source.query?.product ?? source.params?.product);
const venueId = clean(source.venue_id ?? source.venueId ?? source.query?.venue_id ?? source.query?.venueId ?? source.params?.venue_id ?? source.params?.venueId);
const btn = clean(source.btn ?? source.british_tennis_number ?? source.query?.btn ?? source.query?.british_tennis_number ?? source.params?.btn ?? source.params?.british_tennis_number);
const requestSource = clean(source.request_source ?? source.requestSource ?? source.query?.request_source ?? source.query?.requestSource ?? source.params?.request_source ?? source.params?.requestSource) || 'metabase_missing_signup';
return [{ json: { member, product, venue_id: venueId, btn, request_source: requestSource } }];

const created = $('Create Missing Signup Row').first()?.json ?? {};
const batch = $('Execute Create Signup Batch').first()?.json ?? {};
return [{ json: { message: created.message, action: created.action, signup_id: created.signup_id ?? null, member: created.member ?? null, product: created.product ?? null, source: created.source ?? null, batch_message: batch.message ?? null, batch_id: batch.batch_id ?? null, signup_count: batch.signup_count ?? null, response_code: created.response_code ?? 200 } }];

